import time
import anthropic

client = anthropic.Anthropic()

def call_with_retry(messages, model="claude-sonnet-4-6", max_retries=5):
    for attempt in range(max_retries):
        try:
            return client.messages.create(
                model=model,
                max_tokens=1024,
                messages=messages,
            )
        except anthropic.RateLimitError as e:
            if attempt == max_retries - 1:
                raise
            # Use the server-specified wait time when available
            retry_after = e.response.headers.get("retry-after")
            wait = float(retry_after) if retry_after else (2 ** attempt)
            print(f"Rate limited. Waiting {wait:.1f}s (attempt {attempt + 1})")
            time.sleep(wait)

message = call_with_retry([{"role": "user", "content": "Hello"}])
print(message.content[0].text)

import anthropic

client = anthropic.Anthropic()

try:
    client.messages.create(
        model="claude-sonnet-4-6",
        max_tokens=1024,
        messages=[{"role": "user", "content": "Summarize this document: " + "x" * 50000}],
    )
except anthropic.RateLimitError as e:
    msg = str(e).lower()
    if "request" in msg:
        print("Hit RPM limit — reduce concurrent requests or add delays between calls")
    elif "input" in msg:
        print("Hit ITPM limit — shorten prompts, use caching, or spread requests over time")
    elif "output" in msg:
        print("Hit OTPM limit — reduce max_tokens or throttle generation-heavy workloads")
    elif "day" in msg:
        print("Hit daily TPD limit — schedule batch work earlier in the UTC day")
